data.usage#Usage:
Blocks compose core components with sensible defaults:
import { DataPageLayout, FilterBar, StatsRow } from '@mfe/blocks';
import { DataGrid } from '@mfe/x-data-grid';
function InvoicesPage() {
  return (
    <DataPageLayout
      title="Invoices"
      stats={<StatsRow items={kpis} />}
      filters={<FilterBar filters={filterConfig} />}
    >
      <DataGrid rows={invoices} columns={columns} />
    </DataPageLayout>
  );
}

data.customization#Customization:
Override block defaults via props or wrap with custom styles:
<PageHeader
  title="Dashboard"
  breadcrumbs={[{ label: 'Home', href: '/' }, { label: 'Dashboard' }]}
  actions={<Button>Export</Button>}
/>

data.first-component#First Component:
Wrap your application with ThemeProvider and start using components:
import { ThemeProvider, Button, TextField } from '@mfe/design-system';
function App() {
  return (
    <ThemeProvider>
      <TextField label="Email" variant="outlined" />
      <Button variant="contained">Submit</Button>
    </ThemeProvider>
  );
}

data.theming#Theming:
Create a custom theme by extending the default tokens:
import { createTheme, ThemeProvider } from '@mfe/design-system';
const theme = createTheme({
  palette: {
    primary: { main: '#1a56db' },
    secondary: { main: '#6b7280' },
  },
  shape: { borderRadius: 8 },
});
function App() {
  return (
    <ThemeProvider theme={theme}>
      {/* Your app */}
    </ThemeProvider>
  );
}

data.typescript-support#TypeScript Support:
All components ship with full TypeScript declarations. Extend theme types
for custom tokens:
declare module '@mfe/design-system' {
  interface PaletteOptions {
    brand?: { main: string; light: string; dark: string };
  }
}

data.quick-start#Quick Start:
pnpm add @mfe/design-system
import { Button, ThemeProvider } from '@mfe/design-system';
export default function App() {
  return (
    <ThemeProvider>
      <Button variant="contained" color="primary">
        Get Started
      </Button>
    </ThemeProvider>
  );
}

data.phase-1--adapter-layer#Phase 1 — Adapter:
Install the @mfe package alongside the existing library.
Create thin adapter components that map old props to new ones:
// Temporary adapter during migration
function LegacyGrid(props: OldGridProps) {
  const columns = mapOldColumnsToNew(props.columns);
  return <DataGrid rows={props.data} columns={columns} />;
}

data.quick-start#Quick Start:
import { DataGrid, useColumnBuilder } from '@mfe/x-data-grid';
const columns = useColumnBuilder<Invoice>()
  .text('invoiceNo', { header: 'Invoice #', pinned: 'left' })
  .currency('amount', { header: 'Amount' })
  .date('dueDate', { header: 'Due Date' })
  .status('status', { variants: ['draft', 'sent', 'paid'] })
  .build();
<DataGrid rows={invoices} columns={columns} variant="compact" />

data.server-side-data#Server-Side Data:
For large datasets, enable server-side row model:
<DataGrid
  rows={[]}
  columns={columns}
  serverSide
  datasource={serverDatasource}
  cacheBlockSize={100}
/>

